UPDATE pages
SET title = 'Giới thiệu',
    summary = 'Thong tin tong quan ve doanh nghiep, tam nhin, doi ngu va qua trinh phat trien cua Hanoi Survey.',
    content = '',
    status = 'PUBLISHED',
    published_at = COALESCE(published_at, NOW()),
    template_code = 'about_company',
    content_json = '{"hero":{"title":"Về chúng tôi","backgroundImagePath":""},"intro":{"heading":"Doi tac tin cay trong nganh khao sat xay dung","imagePath":"","content":"<p class=\"ql-align-justify\"><strong>CÔNG TY CỔ PHẦN TƯ VẤN KHẢO SÁT XÂY DỰNG HÀ NỘI</strong>&nbsp;(HANOI CONTRUCTION SERVEY CONSULTANT JOIN STOCK COMPANY) là một doanh nghiệp độc lập, tự hào với bề dày kinh nghiệm trong lĩnh vực tư vấn xây dựng.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Được thành lập từ năm 2006, chúng tôi cam kết mang lại những giải pháp tư vấn chất lượng cao, đáp ứng các tiêu chuẩn khắt khe nhất của ngành xây dựng Việt Nam.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Với sở hữu Trung tâm thí nghiệm và kiểm định xây dựng đạt chuẩn, VietDelta tự tin là đối tác tin cậy cho mọi công trình.</p><p class=\"ql-align-justify\"><br></p><p><strong style=\"color: rgb(0, 64, 128);\">Người đại diện:</strong>&nbsp;Đỗ Xuân Dân – Giám đốc Công ty</p>"},"coreValues":{"sectionTitle":"Sứ mệnh và tầm nhìn","items":[{"title":"Sứ mệnh","icon":"bullseye","description":"Cung cấp dữ liệu khảo sát và thí nghiệm chính xác, minh bạch, giúp tối ưu giải pháp nền móng và giảm thiểu rủi ro kỹ thuật cho mọi công trình."},{"title":"Tầm nhìn","icon":"eye","description":"Trở thành đơn vị khảo sát và quan trắc được ưu tiên lựa chọn trong các dự án hạ tâng, công nghiệp và phát triển đô thị tại Việt Nam."},{"title":"Giá trị cốt lõi","icon":"gem","description":"Chúng tôi coi chất lượng dữ liệu, tốc độ phối hợp và trách nhiệm nghề nghiệp là nền tảng của mọi dự án."}]},"timeline":{"sectionTitle":"Quá trình phát triển","items":[{"year":"2006","title":"Khởi đầu","description":"Thành lập công ty tại Định Công, Hoàng Mai, Hà Nội. Đặt nền móng đầu tiên cho hành trình tư vấn xây dựng.","sortOrder":1},{"year":"2007","title":"Mở rộng năng lực Lab","description":"Thành lập Trung tâm thí nghiệm và kiểm định xây dựng.\n\nĐược cấp quyết định công nhận khả năng thực hiện các phép thử số 1232/QĐ-BXD.","sortOrder":2},{"year":"2024 - Nay","title":"Tăng trưởng bền vững","description":"Tham gia nhieu du an trong diem ve giao thong, cong nghiep va phat trien do thi voi goi dich vu khao sat tron goi.","sortOrder":4}]},"organization":{"sectionTitle":"Cơ cấu tổ chức","heading":"Tổ chức khoa học để triển khai nhanh và kiểm soát chất lượng","description":"Mô hình vận hành được phân tách rõ giữa khối điều hành, khối kỹ thuật và các đội hiện trường, giúp doanh nghiệm duy trì tiến độ, bảo đảm chất lượng dữ liệu và tăng khả năng phối hợp trên công trường.","chartImagePath":"","chartCaption":"Sơ đồ tổ chức nhân sự","departments":["Ban Giám đốc và Hội đồng quản trị","Phòng Kỹ thuật - Nghiên cứu và Phát triển","Phòng Thí nghiệm và Kiểm định chất lượng","Phòng Thiết kế và Xây lấp","Phòng Hành chính - Nhân sự và Kế toán","Các đội thi công hiện trường"]},"capability":{"sectionTitle":"Hồ sơ năng lực","heading":"Năng lực và chứng chỉ của chúng tôi","description":"Chúng tôi duy trì đầy đủ hồ sơ pháp lý, năng lục hành nghề và các tài liệu kỹ thuật cần thiết để tham gia nhiều loại hình dự án từ dân dụng đến hạ tầng kỹ thuật.","imagePath":"uploads/2026-04-11/8ad682f4-890d-4bff-8c0f-7c57ffb69739.jpg","items":[{"title":"Giấy phép đăng ký kinh doanh","pdfFilePath":"uploads/2026-04-11/04dcb4b3-65a6-4bd0-81dd-f71ec2f43cbd.pdf","buttonLabel":"Xem PDF"},{"title":"Chứng chỉ năng lực hoạt động khảo sát xây dựng","pdfFilePath":"uploads/2026-04-11/f3bea515-17aa-4dc3-b3e2-e4cc626536fa.pdf","buttonLabel":"Xem PDF"},{"title":"Chứng nhận hệ thống quản lý chất lượng","pdfFilePath":"uploads/2026-04-11/89427367-90ea-4c6d-96b5-30d9e5cb4f58.pdf","buttonLabel":"Xem PDF"},{"title":"Hồ sơ kinh nghiệm các dự án tiêu biểu","pdfFilePath":"","buttonLabel":"Xem PDF"}]}}'
WHERE slug = 'gioi-thieu';

